pragma solidity ^0.8.0;

contract UniqueSignature {
    mapping(address => mapping(uint256 => bool)) public usedSignatures;
    mapping(address => uint256) public nonces;

    event ActionExecuted(address indexed user, uint256 indexed nonce);

    function executeAction(uint256 nonce, bytes memory signature) public {
        require(!usedSignatures[msg.sender][nonce], "Signature already used");
        bytes32 message = keccak256(abi.encodePacked(msg.sender, nonce));
        require(recoverSigner(message, signature) == msg.sender, "Invalid signature");

        usedSignatures[msg.sender][nonce] = true;
        nonces[msg.sender]++;

        emit ActionExecuted(msg.sender, nonce);
    }

    function recoverSigner(bytes32 message, bytes memory signature) internal pure returns (address) {
        (bytes32 r, bytes32 s, uint8 v) = splitSignature(signature);
        return ecrecover(message, v, r, s);
    }

    function splitSignature(bytes memory sig) internal pure returns (bytes32 r, bytes32 s, uint8 v) {
        require(sig.length == 65, "Invalid signature length");
        assembly {
            r := mload(add(sig, 32))
            s := mload(add(sig, 64))
            v := byte(0, mload(add(sig, 96)))
        }
    }
}
